var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":null,"text":{"KOREA":"노엘 양, 일어설 수 있겠나?","JPN":"ノエル君、立てるか？","ENG":"Noelle, can you get up?","TWN":"洛艾兒，你能站起來嗎？"},"stage":{"bg":"DORMITORY_1","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"으으…. 세상이 핑핑 돌아요, 사장님….","JPN":"うう……世界がぐるぐる回ってます、社長……","ENG":"Urgh... The world is spinning, Boss...","TWN":"呃呃……整個世界都在轉，老闆……"},"stage":{"bg":"DORMITORY_1","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"라이카, 라이카도 어서 한마디 해요.","JPN":"ライカ、ライカも早く何か言いなさいよ。","ENG":"Laika, you should also say something.","TWN":"萊卡，你也快點說句話吧。"},"stage":{"bg":"DORMITORY_1","slots":{"L":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L8_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"……어, 응.","JPN":"……あ、おお。","ENG":"...Huh? Okay.","TWN":"……喔，嗯。"},"stage":{"bg":"DORMITORY_1","slots":{"L":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"불법침입자라니 무슨 소리야, 꼬맹이.","JPN":"不法侵入者だなんて、何言ってんだよ、おこちゃま。","ENG":"What do you mean trespassing, kid?","TWN":"怎麼能說是非法入侵者呢，小鬼。"},"stage":{"bg":"DORMITORY_1","slots":{"L":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"저 애를 잘 봐. 무기를 들고 다니잖아.","JPN":"あいつを見てみろ。武器を持ってるだろ？","ENG":"Look at her! She's got a weapon!","TWN":"你看看她，手裡還拿著武器呢。"},"stage":{"bg":"DORMITORY_1","slots":{"L":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"내 날카로운 통찰력에 따르면 금품을 노리고 침입한 강도가 틀림없어.","JPN":"私の鋭い洞察力によると、きっと金品を狙って進入してきた強盗だな。","ENG":"With my keen observation skills, she's clearly breaking in to steal valuables.","TWN":"以我敏銳的觀察力來看，他們肯定是因為財迷心竅才登堂入室的強盜！"},"stage":{"bg":"DORMITORY_1","slots":{"L":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"좋은 지적이에요.","JPN":"立派な指摘ね。","ENG":"Good point.","TWN":"你說的沒錯。"},"stage":{"bg":"DORMITORY_1","slots":{"L":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"그런데 제가 던진 헬멧은 왜 피했어요? 빗나가서 또 유리창 깨지면 물어낼 거예요?","JPN":"ところで、どうして私が投げたヘルメットを避けたの？　外れてまたガラス窓が割れたら弁償するつもり？","ENG":"But then, why did you evade the helmet I threw at you? Are you going to pay if it broke the window glass?","TWN":"不過你為什麼要躲開我扔的頭盔？萬一砸破玻璃，你會賠錢嗎？"},"stage":{"bg":"DORMITORY_1","slots":{"L":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"그게 왜 내 탓이냐. 네 조준이 엉터리라 그렇지.","JPN":"なんで人のせいにするんだよ？　あんたの照準がデタラメだからだろ。","ENG":"How would that be my fault? It just shows how bad your aim is.","TWN":"這怎麼能怪我？是你自己扔不準吧？"},"stage":{"bg":"DORMITORY_1","slots":{"L":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L16_1","type":"dialog","speaker":"MINA_FENRIR_CHIEF_NULL","text":{"KOREA":"억지는 그만 부려.","JPN":"屁理屈はそれくらいにして。","ENG":"Give it up, will you?","TWN":"少在那邊混淆視聽。"},"stage":{"bg":"DORMITORY_1","slots":{"L":null,"C":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"MINA_FENRIR_CHIEF_NULL","text":{"KOREA":"헬멧 던진 건 그냥 넘어가 줄게. 어서 여기서 나가.","JPN":"ヘルメットを投げたのは目をつぶってあげるから。早くここから出て行って。","ENG":"I'll forgive you for throwing that helmet, so just leave.","TWN":"扔頭盔的事我不跟你們計較，你們快離開吧。"},"stage":{"bg":"DORMITORY_1","slots":{"L":null,"C":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"나가야 할 건 그쪽이죠. 여긴 우리가 건틀렛 리그에 진출하기 위한 전초기지거든요.","JPN":"出ていくのはそっちでしょう？　ここは私たちがガントレットリーグに進出するための前哨基地なんです。","ENG":"You're the ones who should leave. This is our outpost for the Gauntlet League.","TWN":"該離開的人是你們。這裡是我們為參加聖鎧聯賽所準備的前哨基地。"},"stage":{"bg":"DORMITORY_1","slots":{"L":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"그래. 다 쓰러져 가는 폐가를 정리하느라 엄청 고생했지.","JPN":"そうだ。倒れかかってる廃屋を掃除するのにどんだけ苦労したと思ってんだ。","ENG":"Yeah. Do you know how hard it was to clean up this dump?","TWN":"沒錯！為了收拾這個搖搖欲墜的破房子，我們差點沒累死！"},"stage":{"bg":"DORMITORY_1","slots":{"L":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L24_1","type":"dialog","speaker":"MINA_FENRIR_CHIEF_NULL","text":{"KOREA":"무슨 사정 때문에 이러는지 몰라도, 너희들이 지금 하는 짓은 범죄야.","JPN":"どういう事情があるのかは知らないけど、あなたたちのやってることは犯罪だよ。","ENG":"I don't care what your reasons are, but you're committing a crime right now. ","TWN":"不管你們這麼做的原因是什麼，但你們現在的行為是犯罪。"},"stage":{"bg":"DORMITORY_1","slots":{"L":null,"C":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"MINA_FENRIR_CHIEF_NULL","text":{"KOREA":"계속 안 나가고 버티면 경찰을 부르겠어.","JPN":"このまま出て行かないなら、警察を呼ぶから。","ENG":"If you don't leave, I'm going to call the police.","TWN":"如果你們堅持不肯離開，我就報警了。"},"stage":{"bg":"DORMITORY_1","slots":{"L":null,"C":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"할말 없으니까 공권력을 동원하겠다는 건가요? 쓰레기 같은 어른이네요.","JPN":"対話では勝ち目がないから、公権力を動員するってことですか？　クズな大人ですね。","ENG":"Oh, you have nothing to say, so you're bringing cops into this? What a scumbag of an adult!","TWN":"說不過人家就要動用公共權力嗎？真是卑鄙的大人。"},"stage":{"bg":"DORMITORY_1","slots":{"L":null,"C":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_HATE"},"R":null}}}]`);export{e as default};